+    init_test("net_tcp_005_large_transfer");
+
+    const DATA_SIZE: usize = 100_000; // 100KB
+
+    let result = block_on(async {
+        let listener = TcpListener::bind("127.0.0.1:0").await?;
+        let addr = listener.local_addr()?;
+
+        // Generate test data
